        def rot13(text):
            result = []
            for char in text:
                if char.isalpha():
                    base = ord('A') if char.isupper() else ord('a')
                    result.append(chr((ord(char) - base + 13) % 26 + base))
                else:
                    result.append(char)
            return ''.join(result)
